// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, powerClass bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log             io.Writer
	CleanupLog      io.Writer
	CleanupRunner   executionCleanupRunner
	ResourceChecker ExecutionResourceChecker
	CleanupInterval time.Duration
	CleanupTickCh   <-chan time.Time
	EventSink       io.Writer
	ProgressCh      chan<- ProgressEvent
	PreClaimHook    func(ctx context.Context) error
	// PreClaimIntakeHook runs after routing preflight and before Claim. It
	// classifies the candidate for actionability/scope; only
	// actionable_atomic proceeds directly to Claim. Non-atomic outcomes
	// skip the bead without claim. intake_error fail-opens so infrastructure
	// failures do not become hidden dispatch failures.
	PreClaimIntakeHook    PreClaimIntakeHook
	PreDispatchLintHook   func(ctx context.Context, beadID string) (LintResult, error)
	PostAttemptTriageHook func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error)
	// ProseEvidenceHook runs after a successful (landed) attempt and before
	// CloseWithEvidence so docs-changing attempts attach advisory prose-check
	// evidence to the bead's event history. Errors are logged and ignored;
	// prose findings never block closure.
	ProseEvidenceHook ProseEvidenceHook
	// PostAttemptDecompositionHook is called when a no_changes attempt signals
	// orchestrator_action: decompose in its rationale, indicating the bead is too
	// large for implementation-level splitting. The hook should run the same
	// orchestrator splitter used by the intake gate and return child specs and an
	// AC map. A nil return or error falls back to operator-required parking.
	PostAttemptDecompositionHook func(ctx context.Context, beadID string) (*PreClaimDecomposition, error)
	// ReviewCostCap, when non-nil, accumulates reviewer cost on the same
	// loop budget tracker used by the implementer attempts.
	ReviewCostCap *escalation.CostCapTracker
	// RoutePreflight, when non-nil, runs once during Run bootstrap before
	// the drain loop starts. It is expected to call upstream ResolveRoute
	// against the loop's resolved (harness, model) and return whatever typed
	// routing error the upstream surfaced — notably
	// agent.ErrHarnessModelIncompatible when the harness allow-list rejects
	// the model. Any non-nil error stops the worker before any bead is
	// claimed; DDx does NOT duplicate the upstream allow-list.
	RoutePreflight func(ctx context.Context, harness, model string) error
	// PreClaimTimeout bounds the pre-claim readiness hooks. Zero means use the
	// binary default so a hanging readiness check cannot park the worker
	// forever.
	PreClaimTimeout time.Duration
	// PreClaimWarnRepeatThreshold is the number of consecutive pre-claim warn
	// fingerprints across distinct bead IDs that trips the operator-attention
	// guard. Zero means use DefaultPreClaimWarnRepeatThreshold.
	PreClaimWarnRepeatThreshold int
	// RouteResolutionTimeout bounds the routing preflight (RoutePreflight) and
	// the resolveRoute viability check so a hung resolver cannot wedge the
	// single-threaded worker for hours while a lease is held (ddx-8f2e0ebf).
	// Zero means use DefaultRouteResolutionTimeout (60s).
	RouteResolutionTimeout time.Duration
	// ConsecutiveWedgeThreshold is the number of consecutive wedges
	// (route_resolution_timeout / progress_watchdog) on the same bead that
	// trips the consecutive-wedge guard: the worker stops re-claiming the bead
	// and parks it for operator attention. Zero means use
	// DefaultConsecutiveWedgeThreshold (2) (ddx-9714eaac).
	ConsecutiveWedgeThreshold int
	// ClaimSuccessRateWindow and ClaimSuccessRateThreshold control the rolling
	// claim-throughput warning emitted by ddx work. A full window whose claim
	// success rate is at or below the configured threshold triggers a single
	// operator-visible warning until a later successful claim clears the warned
	// state.
	ClaimSuccessRateWindow    int
	ClaimSuccessRateThreshold float64
	// BudgetStop, when non-nil, is checked before selecting the next bead. It
	// lets CLI/server callers surface already-tripped budget state as a typed
	// work-layer StopCondition before any new bead is claimed. The companion
	// report is still appended for operator visibility, but the stop itself is
	// classified through work.StopConditionBudget.
	BudgetStop func() (work.StopDecision, ExecuteBeadReport, bool)
	// BinaryRefreshCheck, when non-nil, is checked before selecting the next
	// bead. A true result means the caller has started a replacement worker
	// with equivalent arguments and this loop should exit before claiming work.
	// Errors are logged and fail open so update-probing never blocks the queue.
	BinaryRefreshCheck func(ctx context.Context) (bool, error)
	// ProjectRootDirtyCheck, when non-nil, is called at the top of each loop
	// iteration before any bead is claimed. A non-empty return value means the
	// canonical project root has uncommitted tracked non-.ddx changes. The
	// worker emits loop.operator_attention and stops instead of proceeding to
	// claim. Repeated exits for the same dirty path-set are tracked durably so
	// a relaunch can escalate into a cooldown instead of spinning immediately.
	ProjectRootDirtyCheck func(projectRoot string) []string
	// ServerHealthProbe, when non-nil, is used while the worker is in
	// server-unavailable backoff. Healthy should return true only after /api/health
	// succeeds and the lightweight smoke path is confirmed usable again.
	ServerHealthProbe func(ctx context.Context) (bool, error)
	// ServerFailureWindow bounds the distinct-bead lookback used to detect
	// repeated no_viable_provider outcomes that should be treated as a server-level
	// outage rather than a bead-level failure. Zero means use the documented
	// 10-minute default.
	ServerFailureWindow time.Duration
	// ServerFailureThreshold is the number of distinct beads that must report
	// no_viable_provider inside ServerFailureWindow before the worker enters the
	// server-unavailable probe-and-resume state. Zero means use the documented
	// default of 3.
	ServerFailureThreshold int
	// ServerHealthProbeInterval is the cadence used while the worker is in the
	// server-unavailable state. Zero means use the documented 30s default.
	ServerHealthProbeInterval time.Duration
	// Mode and IdleInterval are the runtime loop intent. Once and
	// PollInterval remain for older tests/callers but production entry points
	// should set Mode and IdleInterval directly.
	Mode         executeloop.Mode
	IdleInterval time.Duration
	Once         bool
	PollInterval time.Duration
	NoReview     bool
	// PostMergeReview enables the legacy post-land/pre-close review state
	// machine for callers that explicitly opt into that manual flow. The
	// default production close path remains owned by candidate-cycle review.
	PostMergeReview        bool
	LabelFilter            string
	IgnoreCooldown         bool
	CooldownOverrideReason string
	SessionID              string
	WorkerID               string
	ProjectRoot            string
	// TargetBeadID, when non-empty, restricts nextCandidate to only return the
	// named bead from the execution-ready queue. Used by `ddx try <bead-id>`
	// to dispatch a single specific bead through the same claim → executor →
	// land path the queue drain uses. When empty, the picker behaves normally.
	TargetBeadID string
	// WakeCh, when non-nil, signals the idle-poll sleep to return immediately
	// so the loop re-scans the queue. Used by the operator-prompt approve /
	// auto-approve mutations (Story 15) to avoid an idle-interval-sized delay
	// before a freshly-approved bead is claimed. Implementations must send
	// non-blocking (server-side helpers do); the loop only waits for a
	// receive on WakeCh during the idle sleep, never elsewhere.
	WakeCh <-chan struct{}

	// FinalizeDurableAudit, when non-nil, is called once per finalized attempt
	// after the loop has finished writing the attempt's durable tracker state.
	// Errors are terminal for autonomous work: the worker stops so DDx-managed
	// audit outputs are not left dirty while more beads are claimed.
	FinalizeDurableAudit func(report ExecuteBeadReport) error
	// PostLadderExhaustionHook, when non-nil, is called when a bead's
	// consecutive_ladder_exhaustions counter reaches the auto-recovery
	// threshold (>= 2). A nil hook or Attempted=false result falls through to
	// the existing loop path unchanged.
	PostLadderExhaustionHook PostLadderExhaustionHook
}

func (r ExecuteBeadLoopRuntime) loopIntent() (executeloop.Mode, time.Duration) {
	mode := r.Mode
	if mode == "" {
		if r.Once {
			mode = executeloop.ModeOnce
		} else {
			mode = executeloop.ModeDrain
		}
	}
	idleInterval := r.IdleInterval
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = r.PollInterval
	}
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = 30 * time.Second
	}
	return mode, idleInterval
}

// DefaultRouteResolutionTimeout bounds routing preflight and the resolveRoute
// viability check when ExecuteBeadLoopRuntime.RouteResolutionTimeout is unset.
// A hung resolver previously wedged the single-threaded worker for hours while
// holding a lease (ddx-8f2e0ebf); 60s is short enough to release promptly and
// long enough not to false-trip a slow-but-healthy resolver.
const DefaultRouteResolutionTimeout = 60 * time.Second

// effectiveRouteResolutionTimeout returns the configured route-resolution
// timeout, falling back to DefaultRouteResolutionTimeout when unset.
func (r ExecuteBeadLoopRuntime) effectiveRouteResolutionTimeout() time.Duration {
	if r.RouteResolutionTimeout > 0 {
		return r.RouteResolutionTimeout
	}
	return DefaultRouteResolutionTimeout
}

// DefaultConsecutiveWedgeThreshold is the number of consecutive wedges on the
// same bead that trips the consecutive-wedge guard when
// ExecuteBeadLoopRuntime.ConsecutiveWedgeThreshold is unset. A single transient
// wedge (count 1) stays below the default so the bead remains re-claimable; two
// consecutive wedges sideline it for operator attention (ddx-9714eaac).
const DefaultConsecutiveWedgeThreshold = 2

// effectiveConsecutiveWedgeThreshold returns the configured consecutive-wedge
// threshold, falling back to DefaultConsecutiveWedgeThreshold when unset.
func (r ExecuteBeadLoopRuntime) effectiveConsecutiveWedgeThreshold() int {
	if r.ConsecutiveWedgeThreshold > 0 {
		return r.ConsecutiveWedgeThreshold
	}
	return DefaultConsecutiveWedgeThreshold
}

// DefaultClaimSuccessRateWindow is the number of recent claim attempts used to
// compute the rolling claim-success rate warning.
const DefaultClaimSuccessRateWindow = 10

// effectiveClaimSuccessRateWindow returns the configured claim-success window,
// falling back to DefaultClaimSuccessRateWindow when unset.
func (r ExecuteBeadLoopRuntime) effectiveClaimSuccessRateWindow() int {
	if r.ClaimSuccessRateWindow > 0 {
		return r.ClaimSuccessRateWindow
	}
	return DefaultClaimSuccessRateWindow
}

// DefaultClaimSuccessRateThreshold is the minimum rolling claim-success rate
// before the loop emits a warning. Zero means only a full window of
// non-successes trips the signal.
const DefaultClaimSuccessRateThreshold = 0.0

// effectiveClaimSuccessRateThreshold returns the configured claim-success
// threshold, falling back to DefaultClaimSuccessRateThreshold when unset.
func (r ExecuteBeadLoopRuntime) effectiveClaimSuccessRateThreshold() float64 {
	if r.ClaimSuccessRateThreshold >= 0 {
		return r.ClaimSuccessRateThreshold
	}
	return DefaultClaimSuccessRateThreshold
}

package agent

import "testing"

// TestFailureModeClassifyWorker exercises ClassifyFailureMode against the
// known worker-level signals. The acceptance contract enumerates the full
// set of modes: context_overflow, merge_conflict, test_failure,
// build_failure, timeout, auth_error, no_changes, unknown (plus "" on
// success). Each case names its input so a pattern drift is easy to spot
// in test failures.
func TestFailureModeClassifyWorker(t *testing.T) {
	cases := []struct {
		name     string
		outcome  string
		exitCode int
		errMsg   string
		want     string
	}{
		{"success_clean", ExecuteBeadOutcomeTaskSucceeded, 0, "", ""},
		{"no_changes", ExecuteBeadOutcomeTaskNoChanges, 0, "", FailureModeNoChanges},
		{"no_evidence", ExecuteBeadOutcomeTaskNoEvidence, 0, "", FailureModeNoEvidenceProduced},
		{"no_changes_ignores_error_text", ExecuteBeadOutcomeTaskNoChanges, 0, "build failed", FailureModeNoChanges},

		// Context / long-context hangs.
		{"context_length_exceeded", ExecuteBeadOutcomeTaskFailed, 1,
			"context_length_exceeded: prompt exceeds 200000 tokens", FailureModeContextOverflow},
		{"prompt_too_long", ExecuteBeadOutcomeTaskFailed, 1,
			"Error: prompt is too long for model", FailureModeContextOverflow},
		{"maximum_context", ExecuteBeadOutcomeTaskFailed, 1,
			"request exceeds the maximum context length", FailureModeContextOverflow},

		// Auth / quota.
		{"unauthorized_401", ExecuteBeadOutcomeTaskFailed, 1,
			"401 Unauthorized: invalid API key", FailureModeAuthError},
		{"insufficient_quota", ExecuteBeadOutcomeTaskFailed, 1,
			"insufficient_quota: you have exceeded your current quota", FailureModeAuthError},
		{"rate_limit", ExecuteBeadOutcomeTaskFailed, 1,
			"429 Too Many Requests: rate limit reached", FailureModeAuthError},

		// Timeout.
		{"context_deadline_exceeded", ExecuteBeadOutcomeTaskFailed, 1,
			"context deadline exceeded", FailureModeTimeout},
		{"timed_out", ExecuteBeadOutcomeTaskFailed, 1,
			"agent call timed out after 2h", FailureModeTimeout},

		// Worktree loss: infrastructure lost the isolated attempt checkout
		// before DDx could inspect the result commit.
		{"worktree_lost_chdir", ExecuteBeadOutcomeTaskFailed, 1,
			"failed to read worktree HEAD: git rev-parse HEAD: chdir /tmp/ddx-exec-wt/.execute-bead-wt-ddx-test-attempt: no such file or directory", FailureModeWorktreeLost},

		// Merge conflict (worker-visible when orchestrator surfaces it via
		// Reason/Error). The landing classifier refines this; the worker
		// classifier recognises the text so a pre-landing result is still
		// tagged correctly.
		{"merge_conflict", ExecuteBeadOutcomeTaskFailed, 1,
			"merge conflict in cli/cmd/agent_metrics.go", FailureModeMergeConflict},

		// Build failure: shipped code that does not compile.
		{"go_compile_error", ExecuteBeadOutcomeTaskFailed, 1,
			"undefined: foo.Bar", FailureModeBuildFailure},
		{"build_failed", ExecuteBeadOutcomeTaskFailed, 1,
			"build failed with 3 errors", FailureModeBuildFailure},

		// Test failure.
		{"go_test_fail_marker", ExecuteBeadOutcomeTaskFailed, 1,
			"--- FAIL: TestX (0.01s)", FailureModeTestFailure},
		{"tests_failed", ExecuteBeadOutcomeTaskFailed, 1,
			"tests failed: 3 of 12 assertions did not pass", FailureModeTestFailure},

		// Unknown fallback: non-zero exit with no recognised pattern.
		{"unknown_error", ExecuteBeadOutcomeTaskFailed, 1,
			"something exploded", FailureModeUnknown},
		{"no_error_text_non_zero", ExecuteBeadOutcomeTaskFailed, 137, "",
			FailureModeUnknown},
		{"resolveroute_zero_exit_error", ExecuteBeadOutcomeTaskFailed, 0,
			"ResolveRoute: no viable routing candidate: 3 candidates rejected", FailureModeNoViableProvider},

		// Ordering: timeout wins over test/build keywords when both appear.
		{"timeout_beats_test_failure", ExecuteBeadOutcomeTaskFailed, 1,
			"test timed out after 5m", FailureModeTimeout},
		// Ordering: auth wins over generic keywords.
		{"auth_beats_build", ExecuteBeadOutcomeTaskFailed, 1,
			"401 unauthorized: build failed", FailureModeAuthError},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := ClassifyFailureMode(tc.outcome, tc.exitCode, tc.errMsg)
			if got != tc.want {
				t.Fatalf("ClassifyFailureMode(%q, %d, %q) = %q, want %q",
					tc.outcome, tc.exitCode, tc.errMsg, got, tc.want)
			}
		})
	}
}

func TestFailureModeClassifyWorker_WorktreeLost(t *testing.T) {
	errText := "failed to read worktree HEAD: git rev-parse HEAD: chdir /tmp/ddx-exec-wt/.execute-bead-wt-ddx-test-attempt: no such file or directory"
	got := ClassifyFailureMode(ExecuteBeadOutcomeTaskFailed, 1, errText)
	if got != FailureModeWorktreeLost {
		t.Fatalf("ClassifyFailureMode worktree loss = %q, want %q", got, FailureModeWorktreeLost)
	}
}

// TestFailureModeLandingRefines exercises classifyLandingFailureMode, which
// is how ApplyLandingToResult folds landing-level signals (merge conflict,
// gate failure) into the final failure_mode. A clean merge clears the
// worker's mode; merge conflict and gate failure override it; other
// preserved reasons defer to the worker's classification.
func TestFailureModeLandingRefines(t *testing.T) {
	gateFailTest := []GateCheckResult{{
		DefinitionID: "go-test",
		Required:     true,
		Status:       "fail",
		Stderr:       "--- FAIL: TestX",
	}}
	gateFailBuild := []GateCheckResult{{
		DefinitionID: "go-build",
		Required:     true,
		Status:       "fail",
		Stderr:       "undefined: foo.Bar",
	}}

	cases := []struct {
		name       string
		outcome    string
		reason     string
		gates      []GateCheckResult
		workerMode string
		want       string
	}{
		{"merged_clears_worker_mode", "merged", "", nil, FailureModeUnknown, ""},
		{"no_changes_outcome", "no-changes", "agent made no commits", nil, "", FailureModeNoChanges},
		{"no_evidence_outcome", "no-evidence", "agent exited without a commit or no_changes_rationale.txt", nil, "", FailureModeNoEvidenceProduced},

		{"preserved_merge_conflict", "preserved", "merge conflict", nil, "", FailureModeMergeConflict},
		{"preserved_ff_not_possible", "preserved", "ff-merge not possible", nil, "", FailureModeMergeConflict},
		{"preserved_merge_failed", "preserved", "merge failed", nil, "", FailureModeMergeConflict},

		{"preserved_post_run_build", "preserved", "post-run checks failed", gateFailBuild, "", FailureModeBuildFailure},
		{"preserved_post_run_test", "preserved", "post-run checks failed", gateFailTest, "", FailureModeTestFailure},
		{"preserved_post_run_empty_defaults_to_test", "preserved", "post-run checks failed", nil, "", FailureModeTestFailure},

		{"preserved_agent_execution_failed_keeps_worker", "preserved", "agent execution failed", nil, FailureModeContextOverflow, FailureModeContextOverflow},
		{"preserved_no_merge_keeps_worker", "preserved", "--no-merge specified", nil, FailureModeTimeout, FailureModeTimeout},
		{"preserved_unknown_reason_falls_back_to_unknown", "preserved", "something else", nil, "", FailureModeUnknown},

		{"error_keeps_worker_mode", "error", "agent execution failed", nil, FailureModeAuthError, FailureModeAuthError},
		{"error_unknown_when_worker_empty", "error", "agent execution failed", nil, "", FailureModeUnknown},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := classifyLandingFailureMode(tc.outcome, tc.reason, tc.gates, tc.workerMode)
			if got != tc.want {
				t.Fatalf("classifyLandingFailureMode(%q, %q, %d-gates, %q) = %q, want %q",
					tc.outcome, tc.reason, len(tc.gates), tc.workerMode, got, tc.want)
			}
		})
	}
}

// TestFailureModeApplyLandingToResult verifies that ApplyLandingToResult
// writes the refined failure_mode onto the result, giving callers a single
// unified record. This is the contract callers of result.json depend on.
func TestFailureModeApplyLandingToResult(t *testing.T) {
	// Worker recorded a context overflow; landing then merged the result
	// cleanly (unlikely but possible if the worker bounced mid-run and a
	// retry landed). The landing decision wins: failure_mode clears.
	res := &ExecuteBeadResult{
		BeadID:      "ddx-test",
		BaseRev:     "a",
		ResultRev:   "b",
		ExitCode:    0,
		Outcome:     ExecuteBeadOutcomeTaskSucceeded,
		FailureMode: FailureModeContextOverflow, // carried from a prior attempt
	}
	ApplyLandingToResult(res, &BeadLandingResult{Outcome: "merged"})
	if res.FailureMode != "" {
		t.Fatalf("merged landing should clear FailureMode, got %q", res.FailureMode)
	}

	// Worker succeeded; landing could not merge. FailureMode becomes
	// merge_conflict so measurement can bucket the failure.
	res = &ExecuteBeadResult{
		BeadID:      "ddx-test",
		BaseRev:     "a",
		ResultRev:   "b",
		ExitCode:    0,
		Outcome:     ExecuteBeadOutcomeTaskSucceeded,
		FailureMode: "",
	}
	ApplyLandingToResult(res, &BeadLandingResult{Outcome: "preserved", Reason: "merge conflict"})
	if res.FailureMode != FailureModeMergeConflict {
		t.Fatalf("merge conflict landing should set merge_conflict, got %q", res.FailureMode)
	}

	// Worker succeeded; gate failed with a build diagnostic in stderr.
	res = &ExecuteBeadResult{
		BeadID:    "ddx-test",
		BaseRev:   "a",
		ResultRev: "b",
		ExitCode:  0,
		Outcome:   ExecuteBeadOutcomeTaskSucceeded,
	}
	ApplyLandingToResult(res, &BeadLandingResult{
		Outcome: "preserved",
		Reason:  "post-run checks failed",
		GateResults: []GateCheckResult{{
			DefinitionID: "go-build",
			Required:     true,
			Status:       "fail",
			Stderr:       "undefined: foo.Bar",
		}},
	})
	if res.FailureMode != FailureModeBuildFailure {
		t.Fatalf("build-diagnostic gate failure should set build_failure, got %q", res.FailureMode)
	}

	// No-changes landing outcome always maps to no_changes regardless of
	// what the worker recorded.
	res = &ExecuteBeadResult{
		BeadID:      "ddx-test",
		BaseRev:     "a",
		ResultRev:   "a",
		ExitCode:    0,
		Outcome:     ExecuteBeadOutcomeTaskNoChanges,
		FailureMode: FailureModeNoChanges,
	}
	ApplyLandingToResult(res, &BeadLandingResult{Outcome: "no-changes", Reason: "agent made no commits"})
	if res.FailureMode != FailureModeNoChanges {
		t.Fatalf("no-changes landing should set no_changes, got %q", res.FailureMode)
	}

	res = &ExecuteBeadResult{
		BeadID:      "ddx-test",
		BaseRev:     "a",
		ResultRev:   "a",
		ExitCode:    0,
		Outcome:     ExecuteBeadOutcomeTaskNoEvidence,
		FailureMode: FailureModeNoEvidenceProduced,
	}
	ApplyLandingToResult(res, &BeadLandingResult{Outcome: "no-evidence", Reason: "agent exited without a commit or no_changes_rationale.txt"})
	if res.FailureMode != FailureModeNoEvidenceProduced {
		t.Fatalf("no-evidence landing should set no_evidence_produced, got %q", res.FailureMode)
	}
}

}

// containsAny reports whether s contains any of the given substrings. s is
// assumed to already be lower-cased by the caller.
func containsAny(s string, needles ...string) bool {
	for _, n := range needles {
		if n == "" {
			continue
		}
		if strings.Contains(s, n) {
			return true
		}
	}
	return false
}

// classifyLandingFailureMode computes the final failure_mode for a result
// after the orchestrator has made its landing decision. It prefers
// landing-specific signals (merge conflict, gate failure) over the worker's
// classification and falls back to workerMode for worker-level failures
// (agent execution failed, context overflow, etc.). Returns "" when the
// bead merged cleanly.
func classifyLandingFailureMode(landingOutcome, landingReason string, gateResults []GateCheckResult, workerMode string) string {
	switch landingOutcome {
	case "merged":
		return ""
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	case "error":
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	case "preserved":
		switch {
		case landingReason == "merge conflict" || landingReason == "merge failed" || landingReason == "ff-merge not possible":
			return FailureModeMergeConflict
		case landingReason == "post-run checks failed", strings.HasPrefix(landingReason, PreMergeChecksReason):
			return classifyGateFailure(gateResults)
		case landingReason == RatchetPreserveReason:
			return FailureModeRatchetMiss
		case landingReason == AttemptIntegrityPreserveReason:
			return FailureModeAttemptIntegrity
		case landingReason == OperatorCancelReason:
			return ""
		}
		// Other preserved reasons (e.g. "agent execution failed",
		// "--no-merge specified") defer to the worker's classification.
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	}
	if workerMode != "" {
		return workerMode
	}
	return FailureModeUnknown
}

// classifyGateFailure inspects failed gate results to distinguish
// build_failure from test_failure. Gate definitions that fail to compile
// before running (go build, tsc, cargo build) typically surface build
// diagnostics in stderr; test runners surface test failure markers. When
// ambiguous, defaults to test_failure since the post-run checks gate is
// test-oriented by convention.
func classifyGateFailure(gateResults []GateCheckResult) string {
	for _, gr := range gateResults {
		if gr.Status != "fail" {
			continue
		}
		combined := strings.ToLower(gr.Stdout + "\n" + gr.Stderr)
		if containsAny(combined,
			"build failed",
			"compilation failed",
			"compile error",
			"compilation error",
			"cannot find package",
			"undefined:",
			"undefined reference",
			"syntax error") {
			return FailureModeBuildFailure
		}
	}
	return FailureModeTestFailure
}

