		}))

		require.NoError(t, applyNoChangesSmartRetry(store, "ddx-niflheim-semantic-retry", "worker", out.NoChanges, out.Report.ActualPower, func(actualPower int) (int, error) {
			return actualPower + 1, nil
		}))

