// setupBareOrigin creates a bare repo at originDir and clones it into workDir.
// Returns (workDir, originDir, initialSHA).
func setupBareOrigin(t *testing.T) (workDir, originDir, initialSHA string) {
	t.Helper()

	originDir = t.TempDir()
	workDir = t.TempDir()

	// Init bare origin.
	runGitInteg(t, originDir, "init", "--bare", "-b", "main")

	// Clone into workDir.
	runGitInteg(t, workDir, "clone", originDir, ".")
	runGitInteg(t, workDir, "config", "user.email", "test@ddx.test")
	runGitInteg(t, workDir, "config", "user.name", "DDx Test")

	// Make an initial commit in workDir and push.
	seedFile := filepath.Join(workDir, "seed.txt")
	require.NoError(t, os.WriteFile(seedFile, []byte("seed\n"), 0644))
	runGitInteg(t, workDir, "add", "seed.txt")
	runGitInteg(t, workDir, "commit", "-m", "chore: initial seed")
	runGitInteg(t, workDir, "push", "-u", "origin", "main")

	initialSHA = runGitInteg(t, workDir, "rev-parse", "HEAD")
	return workDir, originDir, initialSHA
}

func agentRepoRoot(t *testing.T) string {
	t.Helper()

	_, file, _, ok := runtime.Caller(0)
	require.True(t, ok, "runtime.Caller(0) must resolve the test file")
	return filepath.Clean(filepath.Join(filepath.Dir(file), "..", ".."))
}

func parseGoFile(t *testing.T, relPath string) *ast.File {
	t.Helper()

	absPath := filepath.Join(agentRepoRoot(t), relPath)
	src, err := os.ReadFile(absPath)
	require.NoError(t, err, "read %s", relPath)

	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, absPath, src, 0)
	require.NoError(t, err, "parse %s", relPath)
	return file
}

func callName(expr ast.Expr) string {
	call, ok := expr.(*ast.CallExpr)
	if !ok {
		return ""
	}
	switch fun := call.Fun.(type) {
	case *ast.Ident:
		return fun.Name
	case *ast.SelectorExpr:
		return fun.Sel.Name
	default:
		return ""
	}
}

func funcCallCounts(fn *ast.FuncDecl) map[string]int {
	counts := map[string]int{}
	if fn == nil || fn.Body == nil {
		return counts
	}
	ast.Inspect(fn.Body, func(n ast.Node) bool {
		call, ok := n.(*ast.CallExpr)
		if !ok {
			return true
		}
		switch fun := call.Fun.(type) {
		case *ast.Ident:
			counts[fun.Name]++
		case *ast.SelectorExpr:
			counts[fun.Sel.Name]++
		}
		return true
	})
	return counts
}

func functionByName(t *testing.T, file *ast.File, name string) *ast.FuncDecl {
	t.Helper()

	for _, decl := range file.Decls {
		fn, ok := decl.(*ast.FuncDecl)
		if ok && fn.Name.Name == name {
			return fn
		}
	}
	require.FailNowf(t, "missing function", "could not find %s", name)
	return nil
}

